using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔬 Research Agent — investigating: \"{topic}\"\n");

// ---------------------------------------------------------------------------
// Notebook – simple in-memory store the agent uses to record findings
// ---------------------------------------------------------------------------
var notebook = new Notebook();

// ---------------------------------------------------------------------------
// Tools exposed to the agent
// ---------------------------------------------------------------------------

[Description("Search the web for a query and return a list of result snippets with URLs. " +
             "Use this to discover information about any topic.")]
static async Task<string> SearchWeb(
    [Description("The search query")] string query,
    CancellationToken cancellationToken)
{
    // Use DuckDuckGo HTML search – no API key required
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
    var html = await http.GetStringAsync(url, cancellationToken);

    // Extract result snippets from the HTML response
    var results = new StringBuilder();
    var titleMatches = Regex.Matches(html, @"<a[^>]+class=""result__a""[^>]*>(.*?)</a>",
        RegexOptions.Singleline);
    var snippetMatches = Regex.Matches(html, @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
        RegexOptions.Singleline);
    var urlMatches = Regex.Matches(html, @"<a[^>]+class=""result__url""[^>]*href=""([^""]+)""",
        RegexOptions.Singleline);

    var count = Math.Min(titleMatches.Count, Math.Min(snippetMatches.Count, 5));
    if (count == 0)
        return "No results found. Try rephrasing the query.";

    for (var i = 0; i < count; i++)
    {
        var title = StripHtml(titleMatches[i].Groups[1].Value);
        var snippet = StripHtml(snippetMatches[i].Groups[1].Value);
        var link = i < urlMatches.Count
            ? WebUtility.HtmlDecode(urlMatches[i].Groups[1].Value).Trim()
            : "";

        results.AppendLine($"[{i + 1}] {title}");
        if (!string.IsNullOrWhiteSpace(link))
            results.AppendLine($"    URL: {link}");
        results.AppendLine($"    {snippet}");
        results.AppendLine();
    }

    return results.ToString();

    static string StripHtml(string s) =>
        WebUtility.HtmlDecode(Regex.Replace(s, "<.*?>", "")).Trim();
}

[Description("Fetch the text content of a web page given its URL. " +
             "Use this to read a specific page discovered through SearchWeb.")]
static async Task<string> FetchPage(
    [Description("Full URL of the page to fetch")] string url,
    CancellationToken cancellationToken)
{
    try
    {
        using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(15) };
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        var html = await http.GetStringAsync(url, cancellationToken);

        // Strip scripts, styles, tags, and collapse whitespace
