        => _notes.Add((title, content, source, DateTime.UtcNow));

    public override string ToString()
    {
        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notebook ({_notes.Count} notes) ===\n");
        for (var i = 0; i < _notes.Count; i++)
        {
            var n = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {n.Title} ---");
            sb.AppendLine(n.Content);
            sb.AppendLine($"Source: {n.Source}");
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

